        &QueryString;

declare @jobName nvarchar(4000), @normName nvarchar(4000)
if exists(select 1 from dmvv where ma_vv = @ma_vv)
  select @jobName = rtrim(isnull(case when @@language = 'V' then ten_vv else ten_vv2 end, '')) from dmvv where ma_vv = @ma_vv
else
  select @jobName = ''
if exists(select 1 from dtcpql where form = @form and ma_so_ct = @ma_so_ct)
  select @normName = rtrim(isnull(case when @@language = 'V' then chi_tieu else chi_tieu2 end, '')) from dtcpql where form = @form and ma_so_ct = @ma_so_ct
else
  select @normName = ''
select 'this._jobName = ''' + replace(replace(@jobName, '\', '\\'), '''', '\''') + '''; this._normName = ''' + replace(@normName, '''', '\''') + '''; this._queryFilterString = ''' + replace(replace(@@queryString, '\', '\\'), '''', '\''') + '''; init$GridQuery$(this);' as message
return




    &XMLWhenReportLoading;
    &XMLWhenReportClosing;




      &DeclareCommandFilter;



        &QueryString;

declare @querySelectClause nvarchar(4000), @queryFormClause nvarchar(4000), @queryWhereClause nvarchar(4000), @q1 nvarchar(4000), @q2 nvarchar(4000), @unitkey nvarchar(4000)
  , @tk_no varchar(256), @tk_no_du varchar(256), @tk_no_gt varchar(256), @tk_co varchar(256), @tk_co_du varchar(256), @tk_co_gt varchar(256)

select @tk_no = '', @tk_no_du = '', @tk_no_gt = '', @tk_co = '', @tk_co_du = '', @tk_co_gt = ''
select @tk_no = tk_no, @tk_no_du = tk_no_du, @tk_no_gt = tk_no_gt, @tk_co = tk_co, @tk_co_du = tk_co_du, @tk_co_gt = tk_co_gt from dtdmct where ma_so = @ma_so_ct
select @querySelectClause = @@textExternal, @queryFormClause = 'left join dmkh b on a.ma_kh = b.ma_kh', @queryWhereClause = '', @q1 = '', @q2 = ''

if @ma_vv <> '' select @queryWhereClause = @queryWhereClause + ' and dbo.ff_IsRelationJob(''' + replace(rtrim(@ma_vv), '''', '''''') + ''', a.ma_vv) <> 0'
  else if @ma_vv_filter <> '' select @queryWhereClause = @queryWhereClause + ' and dbo.ff_IsRelationJob(''' + replace(rtrim(@ma_vv_filter), '''', '''''') + ''', a.ma_vv) <> 0'
    else if @nh_vv1 + @nh_vv2 + @nh_vv3 <> '' begin
      select @queryFormClause = @queryFormClause + ' left join dmvv c on a.ma_vv = c.ma_vv'
      if @nh_vv1 <> '' select @queryWhereClause = @queryWhereClause + ' and c.nh_vv1 like ''' + replace(rtrim(@nh_vv1), '''', '''''') + '%'''
      if @nh_vv2 <> '' select @queryWhereClause = @queryWhereClause + ' and c.nh_vv2 like ''' + replace(rtrim(@nh_vv2), '''', '''''') + '%'''
      if @nh_vv3 <> '' select @queryWhereClause = @queryWhereClause + ' and c.nh_vv3 like ''' + replace(rtrim(@nh_vv3), '''', '''''') + '%'''
    end

if @tk_no = '' select @q1 = '1 = 0'
  else begin
    select @q1 = '(a.ps_no + a.ps_no_nt <> 0 and ' + dbo.FastBusiness$Function$System$GetAccountFilter('a.tk', 'inlist', @tk_no)
    if @tk_no_du <> '' select @q1 = @q1 + ' and ' + dbo.FastBusiness$Function$System$GetAccountFilter('a.tk_du', 'inlist', @tk_no_du)
    select @q1 = @q1 + ')'
  end

if @tk_no_gt = '' select @q2 = '1 = 0'
  else begin
    select @q2 = '(a.ps_no + a.ps_no_nt <> 0 and ' + dbo.FastBusiness$Function$System$GetAccountFilter('a.tk', 'inlist', @tk_no_gt)
    if @tk_no <> '' select @q2 = @q2 + ' and ' + dbo.FastBusiness$Function$System$GetAccountFilter('a.tk_du', 'inlist', @tk_no)
    select @q2 = @q2 + ')'
  end

&FilterInitialize;&FilterQuery;

select @queryWhereClause = '(' + @q1 + ')' + @queryWhereClause + char(251) + '(' + @q2 + ')' + @queryWhereClause
if charindex(char(251), @queryWhereClause) > 0 begin
  select @querySelectClause = @querySelectClause + char(251) + replace(@querySelectClause, 'ps_no', '-ps_no')
  select @queryFormClause = @queryFormClause + char(251) + 'r00$%Partition a with(nolock) ' + @queryFormClause
end

declare @aggregation nvarchar(4000)
select @aggregation = 'sum(ps_no_nt),sum(ps_no)' + char(251) + 'sum(-ps_no_nt),sum(-ps_no)'

exec FastBusiness$Report$GLDetail @@refresh, @@pageIndex, @@pageCount, @@lastPage, @@lastCount, @@firstItem, @@lastItem,
  @querySelectClause, @queryFormClause, @queryWhereClause, @ngay_tu, @ngay_den, @ma_dvcs, @@admin, @@userID, 'ps_no_nt,ps_no', 'a.ps_no_nt,a.ps_no', @aggregation







      &JavascriptReportInit;
      /* <flatten type="Javascript"> */
function init$GridQuery$(g) {
  var a = g._queryFilterString.split(String.fromCharCode(253));
  var ma_vv = a[1], c = '';
  if (ma_vv != '') {c = (g._language == 'v' ? 'vụ việc' : 'Job Detail') + ': ' + ma_vv + ' - ' + g._jobName + ', '};
  g._alterTitle = [null, [['%s', g._normName, true], ['%c', c, true], ['%d1', formatDateView(a[2]), true], ['%d2', formatDateView(a[3]), true]]];
  g._hiddenFields = [{Fields: 'ps_no_nt', Value: (a[10] == '10')}];
}
/* </flatten> */



